class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> result;
        int n = s.length();
        int count[26] = {0};
        for (int i = 0; i < n; i++) {
            count[s[i] - 'a']++;
            if (count[s[i] - 'a'] >= 3) {
                vector<int> interval;
                int start = i;
                int end = i;
                while (i < n && s[i] == s[i - 1]) {
                    start = i;
                    end = i;
                    i++;
                }
                interval.push_back(start);
                interval.push_back(end);
                result.push_back(interval);
            }
        }
        return result;
    }
};
